/* script block 1 */
// ═══════════════════════════════════════════════════════════════════
// STATE
// ═══════════════════════════════════════════════════════════════════
const KEY = 'flow_v3';
let S = {
  // user
  userName: '', userEmoji: '😊', theme: 'dark', accentColor: 'purple',
  onboarded: false,
  profile: { age: '', heightCm: '', weightKg: '' },
  // goals
  goals: { water: 8, waterBaseMl: 0, steps: 10000, calories: 2000, sleep: 8, pomodoros: 4 },
  // today
  today: '',
  water: 0, cupSize: 250, drinkType: '💧 Água',
  tasks: [], timeBlocks: [],
  steps: 0, hr: null, workouts: [], weights: [],
  measures: { waist:'', arm:'', hip:'', height:'' },
  sleepStart: '23:00', sleepEnd: '07:00', sleepQuality: 0, dreamNotes: '',
  meals: [], mealBuilder: [], mealFavs: [], recentFoods: [], macroMode: 'balanced', focusSound: 'lofi', focusVolume: 55,
  habits: [], habitLogs: {},
  mood: 0, gratitude: ['','',''],
  review: ['','',''],
  pomsDone: 0, pomGoal: 4, studySessions: [], studyNotes: '', studyTag: '',
  // history (7 days)
  history: {},
  // meditation
  medMinutes: 5,
};

window.S = S;
const STORAGE_KEYS = [KEY, 'flow_state', 'flowData', 'flow_backup_v24'];

function ensureStateShape(){
  if (!S.goals) S.goals = { water:8, waterBaseMl:0, steps:10000, calories:2000, sleep:8, pomodoros:4 };
  if (!('waterBaseMl' in S.goals)) S.goals.waterBaseMl = 0;
  if (!S.profile) S.profile = { age:'', heightCm:'', weightKg:'' };
  if (!S.history) S.history = {};
  if (!S.habitLogs) S.habitLogs = {};
  if (!S.measures) S.measures = {};
  if (!S.mealBuilder) S.mealBuilder = [];
  if (!S.mealFavs) S.mealFavs = [];
  if (!S.recentFoods) S.recentFoods = [];
  if (!S.timeBlocks) S.timeBlocks = [];
  if (!S.timeBlockRules) S.timeBlockRules = [];
  if (!S.timeBlockSkips) S.timeBlockSkips = [];
  if (!S.calendarBlockSkips) S.calendarBlockSkips = [];
  if (!S.weights) S.weights = [];
  if (!S.workouts) S.workouts = [];
  if (!S.studySessions) S.studySessions = [];
  if (!S.gratitude) S.gratitude = ['','',''];
  if (!S.review) S.review = ['','',''];
  if (!S.tasks) S.tasks = [];
  if (!S.meals) S.meals = [];
  if (!S.habits) S.habits = [];
  if (!S.userEmoji || String(S.userEmoji).length > 4 || /Ã|ð|�/.test(String(S.userEmoji))) S.userEmoji = '😊';
  window.S = S;
}

function readPersistedState(){
  let best = null;
  let bestScore = -1;
  STORAGE_KEYS.forEach(k=>{
    try{
      const raw = localStorage.getItem(k);
      if(!raw) return;
      const parsed = JSON.parse(raw);
      if(!parsed || typeof parsed !== 'object') return;
      const score = Object.keys(parsed).length + (parsed.onboarded ? 1000 : 0) + (parsed.userName ? 100 : 0) + (parsed.history ? Object.keys(parsed.history).length : 0);
      if(score > bestScore){ best = parsed; bestScore = score; }
    }catch(e){}
  });
  return best;
}

function save(){
  try{
    ensureStateShape();
    const payload = JSON.stringify(S);
    STORAGE_KEYS.forEach(k=>{ try{ localStorage.setItem(k, payload); }catch(e){} });
  }catch(e){}
}

function load() {
  try {
    const d = readPersistedState();
    if (d) S = Object.assign(S, d);
    ensureStateShape();
  } catch(e){ ensureStateShape(); }

  const today = new Date().toDateString();
  if (S.today !== today) {
    if (S.today) {
      try { saveHistory(S.today); } catch(e){}
    }
    S.today = today;
    // Preserve user/profile/configuration and recurring structures. Only clear daily activity counters when the calendar day changes.
    S.water = 0;
    S.steps = 0;
    S.meals = [];
    S.mealBuilder = [];
    S.pomsDone = 0;
    S.studySessions = [];
    S.mood = 0;
    S.gratitude = ['','',''];
    S.review = ['','',''];
    S.workouts = [];
    S.hr = null;
    save();
  }
}
function saveHistory(dateStr) {
  const totalCal = S.meals.reduce((s,m)=>s+m.kcal,0);
  const sleepH = getSleepHours();
  const score = calcScore();
  S.history[dateStr] = {
    water: S.water, waterGoalMl: calcWaterGoalMl(), cupSize: S.cupSize, steps: S.steps, calories: totalCal,
    sleep: sleepH, pomos: S.pomsDone, score: score, mood: S.mood
  };
  // keep only 90 days
  const keys = Object.keys(S.history);
  if (keys.length > 90) delete S.history[keys[0]];
}

// ═══════════════════════════════════════════════════════════════════
// NAVIGATION
// ═══════════════════════════════════════════════════════════════════
let curSec = 'overview';
function goSec(name) {
  document.querySelectorAll('.sec').forEach(s=>s.classList.remove('active'));
  document.querySelectorAll('.nav-btn').forEach(n=>n.classList.remove('active'));
  const sec = document.getElementById('sec-'+name);
  const nav = document.getElementById('nav-'+name);
  if (sec) sec.classList.add('active');
  if (nav) nav.classList.add('active');
  else if (['health','sleep','food','habits','mood','settings'].includes(name)) {
    const moreBtn = document.getElementById('nav-more');
    if (moreBtn) moreBtn.classList.add('active');
  }
  document.querySelectorAll('.side-link').forEach(link=>link.classList.toggle('active', link.getAttribute('onclick')?.includes(`'${name}'`)));
  curSec = name;
  window.scrollTo(0,0);
}
function toggleSideMenu(open) {
  const overlay = document.getElementById('sideMenuOverlay');
  const menu = document.getElementById('sideMenu');
  const body = document.getElementById('sideMenuBody');
  if (!overlay || !menu) return;
  overlay.classList.toggle('open', open);
  menu.classList.toggle('open', open);
  menu.setAttribute('aria-hidden', open ? 'false' : 'true');
  document.body.style.overflow = open ? 'hidden' : '';
  document.documentElement.style.overflow = open ? 'hidden' : '';
  if (open && body) requestAnimationFrame(() => body.scrollTop = 0);
}
function openSectionFromMenu(name) {
  toggleSideMenu(false);
  goSec(name);
}
function quickAddWater(){ addWater(1); goSec('water'); }
function updateSpotlight(){
  const tDone = S.tasks.filter(t=>t.done).length;
  const tTotal = S.tasks.length;
  const sleepHours = getSleepHours();
  const score = calcScore();
  const nextPending = S.tasks.find(t=>!t.done);
  const set = (id, val) => { const el=document.getElementById(id); if(el) el.textContent=val; };
  set('ms-water', Math.round(Math.min(S.water/(S.goals.water||1)*100,100))+'%');
  set('ms-focus', (S.pomsDone||0)+'');
  set('ms-tasks', tDone+'/'+tTotal);
  set('ms-steps', S.steps.toLocaleString('pt-BR'));
  const icon = document.getElementById('spotlightIcon');
  const kicker = document.getElementById('spotlightKicker');
  const title = document.getElementById('spotlightTitle');
  const sub = document.getElementById('spotlightSub');
  if(!icon||!kicker||!title||!sub) return;
  if(nextPending){
    icon.textContent='🎯';
    kicker.textContent='Prioridade';
    title.textContent='Próxima ação: '+nextPending.text;
    sub.textContent='Seu melhor próximo passo está definido. Resolver isso agora reduz atrito e limpa o restante do dia.';
  } else if (S.water < S.goals.water/2) {
    icon.textContent='💧';
    kicker.textContent='Autocuidado';
    title.textContent='Sua hidratação está pedindo atenção';
    sub.textContent='Você está com '+S.water+' de '+S.goals.water+' copos. Um registro rápido já melhora seu ritmo geral.';
  } else if (sleepHours && sleepHours < S.goals.sleep) {
    icon.textContent='😴';
    kicker.textContent='Recuperação';
    title.textContent='Hoje vale equilibrar energia e foco';
    sub.textContent='Você dormiu '+sleepHours+'h. Priorize blocos curtos de concentração e pequenas pausas ao longo do dia.';
  } else {
    icon.textContent = score >= 75 ? '🚀' : '⚡';
    kicker.textContent = score >= 75 ? 'Ritmo forte' : 'Organização';
    title.textContent = score >= 75 ? 'Seu dia está bem encaminhado' : 'Você já tem uma boa base para avançar';
    sub.textContent = score >= 75 ? 'Mantenha consistência nas próximas horas para fechar o dia com um resultado excelente.' : 'Use os atalhos abaixo para ganhar tração sem abrir mão de clareza visual.';
  }
}

// ═══════════════════════════════════════════════════════════════════
// ONBOARDING
// ═══════════════════════════════════════════════════════════════════

function getCurrentWeight(){
  if (S.weights && S.weights.length && S.weights[0]?.val) return parseFloat(S.weights[0].val) || 0;
  return parseFloat(S.profile?.weightKg) || 0;
}
function getCurrentHeight(){
  const input = document.getElementById('measHeight');
  return parseFloat(input?.value) || parseFloat(S.measures?.height) || parseFloat(S.profile?.heightCm) || 0;
}
function calcBaseWaterMl(){
  const weight = getCurrentWeight();
  const fromProfile = weight > 0 ? Math.round(weight * 35) : 2000;
  return Math.max(500, parseInt(S.goals?.waterBaseMl,10) || fromProfile);
}
function calcActivityWaterMl(){
  const stepsBonus = Math.floor((S.steps || 0) / 1000) * 120;
  const workoutBonus = (S.workouts || []).filter(w => w.done).length * 400;
  return stepsBonus + workoutBonus;
}
function calcWaterGoalMl(){
  return calcBaseWaterMl() + calcActivityWaterMl();
}
function getWaterGoalCups(){
  return Math.max(1, Math.ceil(calcWaterGoalMl() / Math.max(50, S.cupSize || 250)));
}

function finishOnboard() {
  const name = document.getElementById('ob-name').value.trim();
  const weight = parseFloat(document.getElementById('ob-weight').value);
  const height = parseFloat(document.getElementById('ob-height').value);
  const age = parseInt(document.getElementById('ob-age').value, 10);
  if (!name) { alert('Por favor, insira seu nome!'); return; }
  if (!weight || weight < 20) { alert('Informe seu peso para calcular a meta inicial de água.'); return; }
  if (!height || height < 80) { alert('Informe sua altura para calcular o IMC corretamente.'); return; }
  if (!age || age < 10) { alert('Informe sua idade para concluir a anamnese inicial.'); return; }
  S.userName = name;
  S.profile = { age, heightCm: height, weightKg: weight };
  S.goals.waterBaseMl = Math.round(weight * 35);
  S.goals.calories = +document.getElementById('ob-cal').value || 2000;
  S.goals.steps = +document.getElementById('ob-steps').value || 10000;
  S.goals.sleep = +document.getElementById('ob-sleep').value || 8;
  S.measures.height = String(height);
  const today = new Date().toLocaleDateString('pt-BR');
  S.weights = [{ date: today, val: weight }, ...(S.weights || []).filter(w => w?.val !== weight)];
  if (S.weights.length > 30) S.weights = S.weights.slice(0, 30);
  S.onboarded = true;
  save();
  showApp();
}
function showApp() {
  document.getElementById('onboard').style.display = 'none';
  document.getElementById('hdr').style.display = '';
  document.getElementById('appWrap').style.display = '';
  document.getElementById('mainNav').style.display = '';
  initApp();
}

