function updateGreeting() {
  const now = new Date();
  const days=['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
  const months=['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
  document.getElementById('hdrDate').textContent = days[now.getDay()]+', '+now.getDate()+' '+months[now.getMonth()];
  const h = now.getHours();
  const name = S.userName ? ', '+S.userName.split(' ')[0] : '';
  let greet = h<12?'Bom dia'+name+' 🌅':h<18?'Boa tarde'+name+' ☀️':'Boa noite'+name+' 🌙';
  document.getElementById('greeting').textContent = greet;
  const subs=['Foco e consistência!','Você está indo bem 💪','Mais um dia, mais progresso','Cada hábito conta!'];
  document.getElementById('greetSub').textContent = subs[now.getDay()%subs.length];
  // avatar
  document.getElementById('avatarBtn').textContent = S.userEmoji||'😊';
  document.getElementById('bigAvatar').textContent = S.userEmoji||'😊';
  document.getElementById('profileName').value = S.userName||'';
}

const EMOJIS=['😊','🙂','😎','🤩','🥳','💪','🧠','🚀','⚡','🦊','🐺','🦁','🐉','🌟','🔥'];
let emojiIdx=0;
function changeEmoji(){
  emojiIdx=(emojiIdx+1)%EMOJIS.length;
  S.userEmoji=EMOJIS[emojiIdx];
  save();
  document.getElementById('avatarBtn').textContent=S.userEmoji;
  document.getElementById('bigAvatar').textContent=S.userEmoji;
}

// ═══════════════════════════════════════════════════════════════════
// SCORE
// ═══════════════════════════════════════════════════════════════════
function calcScore() {
  let s=0, max=8;
  const waterMl = S.water * Math.max(50, S.cupSize || 250);
  const waterGoalMl = calcWaterGoalMl();
  if(waterMl>=waterGoalMl) s++;
  else if(waterMl>=waterGoalMl*0.5) s+=0.5;
  if(S.pomsDone>=S.goals.pomodoros) s++;
  else if(S.pomsDone>0) s+=0.5;
  const td=S.tasks.filter(t=>t.done).length, tt=S.tasks.length;
  if(tt>0&&td===tt) s++;
  else if(tt>0&&td/tt>=0.5) s+=0.5;
  if(S.steps>=S.goals.steps) s++;
  else if(S.steps>=S.goals.steps*0.5) s+=0.5;
  const sh=getSleepHours();
  if(sh>=S.goals.sleep) s++;
  else if(sh>=S.goals.sleep*0.8) s+=0.5;
  const cal=S.meals.reduce((a,m)=>a+m.kcal,0);
  if(cal>0&&cal<=S.goals.calories*1.1) s++;
  else if(cal>0) s+=0.5;
  if(S.mood>=4) s++;
  else if(S.mood>0) s+=0.5;
  const hd=S.habits.filter(h=>S.habitLogs[S.today+'_'+h.id]);
  if(S.habits.length>0&&hd.length===S.habits.length) s++;
  else if(hd.length>0) s+=0.5;
  const pct=Math.round(s/max*100);
  const el=document.getElementById('scoreNum');
  if(el){
    el.textContent=pct+'%';
    el.style.color=pct>=80?'var(--health)':pct>=50?'var(--habits)':'var(--text)';
  }
  document.getElementById('ovScore').textContent=pct+'%';
  return pct;
}

