// ═══════════════════════════════════════════════════════════════════
// STREAK
// ═══════════════════════════════════════════════════════════════════
function updateStreak(){
  const keys=Object.keys(S.history).sort();
  let streak=0;
  const today=new Date();
  for(let i=keys.length-1;i>=0;i--){
    const d=new Date(keys[i]);
    const diff=Math.round((today-d)/(1000*60*60*24));
    if(diff<=streak+1&&S.history[keys[i]].score>=50){streak++;} else break;
  }
  const banner=document.getElementById('streakBanner');
  if(streak>=2){
    banner.classList.add('show');
    document.getElementById('streakText').textContent=streak+' dias seguidos!';
  } else { banner.classList.remove('show'); }
}

// ═══════════════════════════════════════════════════════════════════
// WATER
// ═══════════════════════════════════════════════════════════════════
let lastDrank = Date.now();
function renderWater(){
  syncCupSizeUI();
  const goalMl = calcWaterGoalMl();
  const goalCups = getWaterGoalCups();
  S.goals.water = goalCups;
  document.getElementById('waterNum').textContent=S.water;
  const ml=S.water*S.cupSize;
  document.getElementById('waterUnit').innerHTML=`copos &bull; ${ml}ml / <span id="waterGoalDisp">${goalMl}</span>ml`;
  document.getElementById('waterBar').style.width=Math.min(ml/goalMl*100,100)+'%';
  document.getElementById('waterMl').textContent=ml+'ml';
  document.getElementById('waterMax').textContent=goalMl+'ml';
  const wrap=document.getElementById('waterCups'); wrap.innerHTML='';
  for(let i=0;i<goalCups;i++){
    const c=document.createElement('div');
    c.className='cup'+(i<S.water?' fill':'');
    c.textContent='💧';
    c.onclick=()=>{ S.water=i<S.water?i:i+1; lastDrank=Date.now(); save(); renderWater(); calcScore(); renderOverview(); };
    wrap.appendChild(c);
  }
  const hist=Object.keys(S.history).slice(-7);
  let wStr=0;
  for(const k of [...hist].reverse()){
    const target = S.history[k]?.waterGoalMl || goalMl;
    const actual = (S.history[k]?.water || 0) * (S.history[k]?.cupSize || S.cupSize || 250);
    if(actual>=target) wStr++; else break;
  }
  if(ml>=goalMl) wStr++;
  const wse=document.getElementById('waterStreak');
  if(wse) wse.textContent=wStr>0?'🔥 '+wStr+' dias':'';
  calcScore(); renderOverview();
}
function addWater(d){
  const maxCups = Math.max(getWaterGoalCups()*2, 1);
  S.water=Math.max(0,Math.min(maxCups,S.water+d));
  if(d>0) lastDrank=Date.now();
  save(); renderWater();
}
function setDrink(el){
  document.querySelectorAll('#drinkTabs .chip').forEach(c=>c.classList.remove('on'));
  el.classList.add('on');
  S.drinkType=el.dataset.drink; save();
}
function setCupSize(el,ml){
  document.querySelectorAll('#cupSizeTabs .chip').forEach(c=>c.classList.remove('on'));
  if(el) el.classList.add('on');
  S.cupSize=ml; save(); renderWater();
}
function focusCustomCup(){
  document.querySelectorAll('#cupSizeTabs .chip').forEach(c=>c.classList.remove('on'));
  const chip=document.querySelector('#cupSizeTabs [data-ml="custom"]');
  if(chip) chip.classList.add('on');
  const inp=document.getElementById('customCupSize');
  if(inp){ inp.value=S.cupSize||''; inp.focus(); inp.select(); }
}
function applyCustomCupSize(){
  const inp=document.getElementById('customCupSize');
  const ml=parseInt(inp?.value,10);
  if(!ml || ml<50 || ml>3000) return;
  S.cupSize=ml; save(); renderWater();
}
function syncCupSizeUI(){
  const inp=document.getElementById('customCupSize');
  if(inp) inp.value=S.cupSize||250;
  const chips=[...document.querySelectorAll('#cupSizeTabs .chip')];
  chips.forEach(c=>c.classList.remove('on'));
  const preset=document.querySelector(`#cupSizeTabs .chip[data-ml="${S.cupSize}"]`);
  if(preset) preset.classList.add('on');
  else {
    const custom=document.querySelector('#cupSizeTabs .chip[data-ml="custom"]');
    if(custom) custom.classList.add('on');
  }
}
function checkWaterAlert(){
  const diff=(Date.now()-lastDrank)/1000/60/60;
  const card=document.getElementById('waterAlertCard');
  if(card) card.style.display=diff>2&&S.water<S.goals.water?'':'none';
  setTimeout(checkWaterAlert,60000);
}

// ═══════════════════════════════════════════════════════════════════
// POMODORO
// ═══════════════════════════════════════════════════════════════════
let tInterval=null, tRunning=false, tSecs=25*60, tMode='focus';
let sessionStart=null;
const MODES={focus:25*60,short:5*60,long:15*60,deep:50*60};
const MLABELS={focus:'Foco · 25 minutos',short:'Pausa curta · 5 min',long:'Pausa longa · 15 min',deep:'Deep Work · 50 minutos'};
function setMode(m,el){
  tMode=m; tSecs=MODES[m]; tRunning=false; clearInterval(tInterval);
  document.getElementById('timerBtn').textContent='▶ Iniciar';
  document.getElementById('timerModeLabel').textContent=MLABELS[m];
  document.getElementById('timerPhase').textContent='pronto para começar';
  document.getElementById('timerDisp').style.color='var(--study)';
  document.querySelectorAll('#sec-study .chip').forEach(c=>c.classList.remove('on'));
  if(el) el.classList.add('on');
  renderTimerDisp();
}
function renderTimerDisp(){
  const m=Math.floor(tSecs/60),s=tSecs%60;
  document.getElementById('timerDisp').textContent=String(m).padStart(2,'0')+':'+String(s).padStart(2,'0');
}
function toggleTimer(){
  if(tRunning){
    clearInterval(tInterval); tRunning=false;
    document.getElementById('timerBtn').textContent='▶ Continuar';
    document.getElementById('timerPhase').textContent='pausado';
  } else {
    tRunning=true; sessionStart=sessionStart||Date.now();
    document.getElementById('timerBtn').textContent='⏸ Pausar';
    document.getElementById('timerPhase').textContent=tMode==='focus'||tMode==='deep'?'em foco...':'descansando...';
    document.getElementById('timerDisp').style.color=tMode==='focus'||tMode==='deep'?'var(--study)':'var(--health)';
    tInterval=setInterval(()=>{
      tSecs--;
      if(tSecs<=0){
        clearInterval(tInterval); tRunning=false;
        if(tMode==='focus'||tMode==='deep'){
          S.pomsDone++;
          const tag=document.getElementById('studyTag').value||'Sem tag';
          const dur=tMode==='focus'?25:50;
          S.studySessions.push({time:new Date().toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}),tag,dur});
          save(); renderStudySessions(); renderPomBar();
        }
        document.getElementById('timerBtn').textContent='▶ Iniciar';
        document.getElementById('timerPhase').textContent=tMode==='focus'||tMode==='deep'?'✅ Concluído!':'✅ Pausa encerrada!';
        tSecs=MODES[tMode]; sessionStart=null;
        calcScore(); renderOverview();
        // vibrate
        if(navigator.vibrate) navigator.vibrate([200,100,200]);
      }
      renderTimerDisp();
      renderPomDots();
    },1000);
  }
}
function resetTimer(){
  clearInterval(tInterval); tRunning=false; tSecs=MODES[tMode]; sessionStart=null;
  document.getElementById('timerBtn').textContent='▶ Iniciar';
  document.getElementById('timerPhase').textContent='pronto para começar';
  renderTimerDisp();
}
function renderPomDots(){
  const wrap=document.getElementById('pomDots'); if(!wrap) return;
  wrap.innerHTML='';
  const goal=S.goals.pomodoros||4;
  for(let i=0;i<goal;i++){
    const d=document.createElement('div');
    d.className='pom-dot'+(i<S.pomsDone%goal?' done':'')+(i===S.pomsDone%goal&&tRunning?' active':'');
    wrap.appendChild(d);
  }
}
function renderPomBar(){
  const bar=document.getElementById('pomBar'); if(!bar) return;
  const goal=S.goals.pomodoros||4;
  bar.style.width=Math.min(S.pomsDone/goal*100,100)+'%';
  document.getElementById('pomDoneLabel').textContent=S.pomsDone+' pomodoro'+(S.pomsDone!==1?'s':'');
  document.getElementById('pomGoalLabel').textContent='meta: '+goal;
}
function savePomGoal(){
  S.goals.pomodoros=+document.getElementById('pomGoalInput').value||4;
  save(); renderPomBar();
}
function renderStudy(){
  renderPomBar(); renderPomDots(); renderStudySessions();
}
function renderStudySessions(){
  const wrap=document.getElementById('studySessions'); if(!wrap) return;
  if(!S.studySessions||S.studySessions.length===0){wrap.innerHTML='<div class="empty">Nenhuma sessão ainda.</div>';return;}
  const total=S.studySessions.reduce((s,ss)=>s+ss.dur,0);
  document.getElementById('studyTotalTime').textContent=total+'min';
  wrap.innerHTML='';
  S.studySessions.forEach(ss=>{
    const el=document.createElement('div');
    el.className='list-item';
    el.innerHTML=`<span style="font-size:18px">📚</span><div style="flex:1"><div class="li-text">${ss.tag}</div><div class="li-meta">${ss.time} · ${ss.dur}min</div></div>`;
    wrap.appendChild(el);
  });
}

// ═══════════════════════════════════════════════════════════════════
// TASKS
// ═══════════════════════════════════════════════════════════════════
let taskFilter='all';
function addTask(){
  const inp=document.getElementById('taskInp');
  const val=inp.value.trim(); if(!val) return;
  const cat=document.getElementById('taskCat').value;
  const prio=document.getElementById('taskPrio').value;
  const due=document.getElementById('taskDue').value;
  S.tasks.push({id:Date.now(),text:val,done:false,cat,prio,due,subtasks:[],notes:''});
  inp.value=''; save(); renderTasks(); renderOverview();
}
function toggleTask(id){
  const t=S.tasks.find(t=>t.id===id); if(!t) return;
  t.done=!t.done; save(); renderTasks();
  if(S.tasks.every(t=>t.done)&&S.tasks.length>0) confetti();
  calcScore(); renderOverview();
}
function deleteTask(id){ S.tasks=S.tasks.filter(t=>t.id!==id); save(); renderTasks(); renderOverview(); }
function filterTasks(el){
  document.querySelectorAll('#taskFilters .chip').forEach(c=>c.classList.remove('on'));
  el.classList.add('on'); taskFilter=el.dataset.filter; renderTasks();
}
function renderTasks(){
  const list=document.getElementById('tasksList'); if(!list) return;
  let tasks=S.tasks;
  if(taskFilter==='pending') tasks=tasks.filter(t=>!t.done);
  else if(taskFilter==='done') tasks=tasks.filter(t=>t.done);
  else if(taskFilter==='high') tasks=tasks.filter(t=>t.prio==='high');
  else if(taskFilter.includes('💼')||taskFilter.includes('📚')) tasks=tasks.filter(t=>t.cat===taskFilter);
  // sort: high first, then by due
  tasks=[...tasks].sort((a,b)=>{
    const po={high:0,mid:1,low:2};
    return (po[a.prio]||1)-(po[b.prio]||1);
  });
  if(tasks.length===0){list.innerHTML='<div class="empty">Nenhuma tarefa aqui.</div>';updateWorkProgress();return;}
  list.innerHTML='';
  tasks.forEach(t=>{
    const el=document.createElement('div');
    el.className='list-item'+(t.done?' done':'');
    const badge=t.prio==='high'?'<span class="badge badge-high">Alta</span>':t.prio==='low'?'<span class="badge badge-low">Baixa</span>':'';
    const dueStr=t.due?'<div class="li-meta">⏰ '+formatDue(t.due)+'</div>':'';
    el.innerHTML=`
      <div class="li-check" onclick="toggleTask(${t.id})">${t.done?'✓':''}</div>
      <div style="flex:1;cursor:pointer" onclick="openTaskDetail(${t.id})">
        <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">
          <span class="li-text">${t.text}</span>${badge}
        </div>
        <div class="li-meta">${t.cat}${dueStr?'':''}</div>
        ${dueStr}
      </div>
      <button class="li-del" onclick="deleteTask(${t.id})">×</button>`;
    list.appendChild(el);
    // subtasks
    if(t.subtasks&&t.subtasks.length>0){
      t.subtasks.forEach((sub,si)=>{
        const sel=document.createElement('div');
        sel.className='subtask';
        sel.innerHTML=`<div class="sub-check ${sub.done?'done':''}" onclick="toggleSub(${t.id},${si})">${sub.done?'✓':''}</div><span class="sub-text ${sub.done?'done':''}">${sub.text}</span>`;
        list.appendChild(sel);
      });
    }
  });
  updateWorkProgress();
}
function formatDue(due){
  const d=new Date(due);
  return d.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'})+' '+d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'});
}
function updateWorkProgress(){
  const done=S.tasks.filter(t=>t.done).length, total=S.tasks.length;
  const pct=total?done/total*100:0;
  const bar=document.getElementById('workBar');
  if(bar) bar.style.width=pct+'%';
  const wd=document.getElementById('workDone'); if(wd) wd.textContent=done+' concluída'+(done!==1?'s':'');
  const wt=document.getElementById('workTotal'); if(wt) wt.textContent=total+' total';
  // category counts
  const cats={};
  S.tasks.forEach(t=>{ cats[t.cat]=(cats[t.cat]||0)+1; });
  const cc=document.getElementById('catCounts');
  if(cc){ cc.innerHTML=''; Object.entries(cats).forEach(([k,v])=>{
    const span=document.createElement('span');
    span.className='badge badge-mid';
    span.textContent=k+': '+v;
    cc.appendChild(span);
  });}
  // next task
  const nextPend=S.tasks.find(t=>!t.done);
  const nw=document.getElementById('nextTaskWrap');
  const nt=document.getElementById('nextTaskText');
  if(nextPend&&nw&&nt){ nw.style.display=''; nt.textContent=nextPend.text; }
  else if(nw) nw.style.display='none';
}
function toggleSub(tid,si){
  const t=S.tasks.find(t=>t.id===tid); if(!t||!t.subtasks) return;
  t.subtasks[si].done=!t.subtasks[si].done; save(); renderTasks();
}
function openTaskDetail(id){
  const t=S.tasks.find(t=>t.id===id); if(!t) return;
  const wrap=document.getElementById('taskModalContent');
  wrap.innerHTML=`
    <div style="font-size:16px;font-weight:700">${t.text}</div>
    <div style="font-size:12px;color:var(--muted);font-family:'DM Mono',monospace">${t.cat} · ${t.prio==='high'?'🔴 Alta':t.prio==='low'?'🟢 Baixa':'🟡 Média'}</div>
    <textarea class="inp" id="tdNotes" rows="3" placeholder="Notas..." oninput="S.tasks.find(t=>t.id==${id}).notes=this.value;save()">${t.notes||''}</textarea>


<div style="font-size:12px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:1px">Subtarefas</div>
<div id="subList">${renderSubList(t)}</div>
<div class="inp-row">
  <input class="inp" id="subInp" placeholder="Nova subtarefa..." style="--acc:var(--work)">
  <button class="btn btn-sm" onclick="addSub(${id})">+</button>
</div>`;


document.getElementById('taskModal').classList.add('open');
}
function renderSubList(t){
if(!t.subtasks||t.subtasks.length===0) return '<div class="empty">Nenhuma subtarefa.</div>';
return t.subtasks.map((s,i)=>`<div class="list-item ${s.done?'done':''}"> <div class="li-check" onclick="toggleSub(${t.id},${i});document.getElementById('subList').innerHTML=renderSubList(S.tasks.find(t=>t.id===${t.id}))">${s.done?'✓':''}</div> <span class="li-text">${s.text}</span></div>`).join('');
}
function addSub(tid){
const inp=document.getElementById('subInp'); const val=inp.value.trim(); if(!val) return;
const t=S.tasks.find(t=>t.id===tid); if(!t) return;
if(!t.subtasks) t.subtasks=[];
t.subtasks.push({text:val,done:false}); inp.value=''; save();
document.getElementById('subList').innerHTML=renderSubList(t);
}

// Time blocks
function addTimeBlock(){ document.getElementById('tbModal').classList.add('open'); }
function saveTB(){
const s=document.getElementById('tbStart').value;
const e=document.getElementById('tbEnd').value;
const t=document.getElementById('tbTask').value.trim();
const c=document.getElementById('tbColor').value;
if(!s||!e||!t) return;
S.timeBlocks.push({start:s,end:e,task:t,color:c});
save(); renderTimeBlocks(); closeModal('tbModal');
}
function renderTimeBlocks(){
const wrap=document.getElementById('timeBlocks'); if(!wrap) return;
if(!S.timeBlocks||S.timeBlocks.length===0){wrap.innerHTML='<div class="empty">Nenhum bloco de tempo.</div>';return;}
wrap.innerHTML='';
[...S.timeBlocks].sort((a,b)=>a.start.localeCompare(b.start)).forEach((tb,i)=>{
const el=document.createElement('div');
el.className='tb-slot';
el.innerHTML=`<div class="tb-color" style="background:${tb.color}"></div> <div class="tb-time">${tb.start}<br>${tb.end}</div> <div class="tb-task">${tb.task}</div> <button class="li-del" onclick="S.timeBlocks.splice(${i},1);save();renderTimeBlocks()">×</button>`;
wrap.appendChild(el);
});
}

