function calcIMC(){
const h=getCurrentHeight();
const w=getCurrentWeight();
if(!h||!w){
const iv=document.getElementById('imcVal'); if(iv) iv.textContent='—';
const il=document.getElementById('imcLabel'); if(il) il.textContent='Informe peso e altura';
return;
}
S.measures.height=String(h);
if (S.profile) S.profile.heightCm = h;
const imc=w/((h/100)**2);
const iv=document.getElementById('imcVal'); if(iv) iv.textContent=imc.toFixed(1);
const il=document.getElementById('imcLabel');
if(il){
if(imc<18.5) il.textContent='Abaixo do peso';
else if(imc<25) il.textContent='Normal';
else if(imc<30) il.textContent='Sobrepeso';
else il.textContent='Obesidade';
}
save();
}
