// ═══════════════════════════════════════════════════════════════════
// SLEEP
// ═══════════════════════════════════════════════════════════════════
function getSleepHours(){
const s=document.getElementById('sleepStart'); const e=document.getElementById('sleepEnd');
if(!s||!e) return 0;
const sv=s.value||S.sleepStart; const ev=e.value||S.sleepEnd;
const [sh,sm]=sv.split(':').map(Number);
const [eh,em]=ev.split(':').map(Number);
let mins=(eh*60+em)-(sh*60+sm);
if(mins<0) mins+=24*60;
return parseFloat((mins/60).toFixed(1));
}
function calcSleep(){
const hrs=getSleepHours();
const el=document.getElementById('sleepHrs'); if(el) el.textContent=hrs||'—';
const pct=Math.min(hrs/S.goals.sleep*100,100);
const arc=document.getElementById('sleepArc');
if(arc) arc.style.strokeDashoffset=314-(314*pct/100);
// alarm
const ss=document.getElementById('sleepStart').value||S.sleepStart;
const [sh,sm]=ss.split(':').map(Number);
const wakeMin=(sh*60+sm)+S.goals.sleep*60;
const wh=Math.floor(wakeMin/60)%24, wm=wakeMin%60;
const ag=document.getElementById('alarmSugg');
if(ag) ag.textContent=String(wh).padStart(2,'0')+':'+String(wm).padStart(2,'0');
// debt
const hist7=Object.keys(S.history).slice(-6).map(k=>S.history[k].sleep||0);
hist7.push(hrs);
const debt=Math.max(0,hist7.reduce((s,h)=>s+(S.goals.sleep-h),0));
const de=document.getElementById('sleepDebt');
if(de) de.textContent=debt.toFixed(1)+'h';
// recommendation
const rc=document.getElementById('sleepRecCard');
const re=document.getElementById('sleepRec');
if(rc&&re){
if(hrs<S.goals.sleep-1.5){
rc.style.display='';
re.textContent='😴 Você dormiu pouco ontem. Hoje tente beber mais água e evitar atividades muito intensas. Considere dormir mais cedo esta noite.';
} else if(hrs>=S.goals.sleep){
rc.style.display='';
re.textContent='✨ Ótimo sono! Você está bem descansado. Aproveite a energia de hoje para focar nas suas metas!';
} else { rc.style.display='none'; }
}
S.sleepStart=document.getElementById('sleepStart').value;
S.sleepEnd=document.getElementById('sleepEnd').value;
save(); calcScore(); renderOverview();
}
function setSleepQual(q, sv=true){
S.sleepQuality=q;
document.querySelectorAll('.qual-btn').forEach(b=>b.classList.toggle('sel',+b.dataset.q===q));
if(sv){ save(); }
}


let flowAudioCtx=null, flowMasterGain=null, flowNoiseNode=null, flowNoiseGain=null, flowLfo=null, flowOscs=[];
function ensureFlowCtx(){ if(!flowAudioCtx){ const AC=window.AudioContext||window.webkitAudioContext; if(AC) flowAudioCtx=new AC(); } return flowAudioCtx; }
function makePinkishNoise(ctx){
  const size=2*ctx.sampleRate; const buffer=ctx.createBuffer(1,size,ctx.sampleRate); const out=buffer.getChannelData(0);
  let last=0; for(let i=0;i<size;i++){ const white=Math.random()*2-1; last=(last*0.985)+(0.015*white); out[i]=last*0.9; }
  const src=ctx.createBufferSource(); src.buffer=buffer; src.loop=true; return src;
}
async function startFocusSound(){
  const ctx=ensureFlowCtx(); if(!ctx) return; if(ctx.state==='suspended') await ctx.resume();
  stopFocusAudio();
  flowMasterGain=ctx.createGain(); flowMasterGain.gain.value=((S.focusVolume||45)/100)*0.22;
  const lowpass=ctx.createBiquadFilter(); lowpass.type='lowpass'; lowpass.frequency.value=1200; lowpass.Q.value=0.4;
  const highshelf=ctx.createBiquadFilter(); highshelf.type='highshelf'; highshelf.frequency.value=1800; highshelf.gain.value=-8;
  const compressor=ctx.createDynamicsCompressor(); compressor.threshold.value=-20; compressor.knee.value=18; compressor.ratio.value=2;
  flowMasterGain.connect(lowpass); lowpass.connect(highshelf); highshelf.connect(compressor); compressor.connect(ctx.destination);

  const freqs=[220,329.63,392];
  flowOscs=freqs.map((f,idx)=>{ const osc=ctx.createOscillator(); const gain=ctx.createGain(); const trem=ctx.createGain(); osc.type=idx===0?'triangle':'sine'; osc.frequency.value=f; gain.gain.value=idx===0?0.028:0.018; trem.gain.value=1; osc.connect(gain); gain.connect(trem); trem.connect(flowMasterGain); osc.start(); return {osc,gain,trem}; });
  flowLfo=ctx.createOscillator(); const lfoGain=ctx.createGain(); flowLfo.type='sine'; flowLfo.frequency.value=0.18; lfoGain.gain.value=0.18; flowLfo.connect(lfoGain); flowOscs.forEach(o=>lfoGain.connect(o.trem.gain)); flowLfo.start();

  flowNoiseNode=makePinkishNoise(ctx); flowNoiseGain=ctx.createGain(); flowNoiseGain.gain.value=0.02; const noiseFilter=ctx.createBiquadFilter(); noiseFilter.type='lowpass'; noiseFilter.frequency.value=650; flowNoiseNode.connect(noiseFilter); noiseFilter.connect(flowNoiseGain); flowNoiseGain.connect(flowMasterGain); flowNoiseNode.start();

  focusPlaying=true;
  const btn=document.getElementById('focusAudioBtn'); if(btn) btn.textContent='⏸ Pausar';
  const player=document.getElementById('focusPlayer'); if(player) player.classList.remove('off');
  const status=document.getElementById('focusAudioStatus'); if(status) status.textContent='Lo-fi calmo ativo no app.';
}
function stopFocusAudio(){
  try{ flowOscs.forEach(o=>{o.osc.stop(); o.osc.disconnect();}); }catch(e){}
  try{ if(flowLfo){ flowLfo.stop(); flowLfo.disconnect(); } }catch(e){}
  try{ if(flowNoiseNode){ flowNoiseNode.stop(); flowNoiseNode.disconnect(); } }catch(e){}
  try{ if(flowNoiseGain) flowNoiseGain.disconnect(); }catch(e){}
  try{ if(flowMasterGain) flowMasterGain.disconnect(); }catch(e){}
  flowOscs=[]; flowLfo=null; flowNoiseNode=null; flowNoiseGain=null; flowMasterGain=null;
  focusPlaying=false;
  const btn=document.getElementById('focusAudioBtn'); if(btn) btn.textContent='▶ Tocar';
  const player=document.getElementById('focusPlayer'); if(player) player.classList.add('off');
  const status=document.getElementById('focusAudioStatus'); if(status) status.textContent='Toque em reproduzir para ativar o lo-fi calmo dentro do app.';
}
function setFocusVolume(v){ S.focusVolume=+v; save(); if(flowMasterGain){ flowMasterGain.gain.value=((+v)/100)*0.22; } }
function setFocusSound(mode,el){ S.focusSound='lofi'; save(); document.querySelectorAll('[data-focus-mode]').forEach(c=>c.classList.remove('on')); if(el) el.classList.add('on'); const chip=document.getElementById('focusSoundMode'); if(chip) chip.textContent='Lo-fi calmo'; const ttl=document.getElementById('focusSoundTitle'); if(ttl) ttl.textContent='Flow Lo-fi calmo'; const subt=document.getElementById('focusSoundSub'); if(subt) subt.textContent='Ambiente suave incorporado no próprio app'; if(focusPlaying) startFocusSound(); }

