let focusAudioEl=null, focusPlaying=false;
const FOCUS_AUDIO_SRC={lofi:"data:audio/wav;base64,",rain:"data:audio/wav;base64,"};
function getFocusAudioEl(){
  const mode='lofi';
  return document.getElementById(mode==='rain' ? 'focusAudioRain' : 'focusAudioLofi');
}
function ensureFocusAudioLoaded(mode){
  const id=mode==='rain' ? 'focusAudioRain' : 'focusAudioLofi';
  const el=document.getElementById(id);
  if(el && !el.src) el.src=FOCUS_AUDIO_SRC[mode];
  if(el) el.volume=(S.focusVolume||55)/100;
  return el;
}
async function startFocusSound(){
  stopFocusAudio(true);
  const mode='lofi';
  const el=ensureFocusAudioLoaded(mode);
  focusAudioEl=el;
  try{ await el.play(); focusPlaying=true; }
  catch(err){
    console.error(err);
    const status=document.getElementById('focusAudioStatus');
    if(status) status.textContent='O iPhone/PWA bloqueou a reprodução. Toque novamente em reproduzir.';
    throw err;
  }
  document.getElementById('focusAudioBtn').textContent='⏸ Pausar';
  document.getElementById('focusPlayer')?.classList.remove('off');
  const status=document.getElementById('focusAudioStatus');
  if(status) status.textContent='Lo-fi calmo ativo no app.';
}
function stopFocusAudio(silent=false){
  ['focusAudioLofi'].forEach(id=>{
    const el=document.getElementById(id);
    if(el){ el.pause(); el.currentTime=0; }
  });
  focusPlaying=false; focusAudioEl=null;
  const btn=document.getElementById('focusAudioBtn'); if(btn) btn.textContent='▶ Tocar';
  document.getElementById('focusPlayer')?.classList.add('off');
  if(!silent){
    const status=document.getElementById('focusAudioStatus');
    if(status) status.textContent='Áudio pausado.';
  }
}
async function toggleFocusAudio(){
  if(focusPlaying){ stopFocusAudio(); return; }
  try{ await startFocusSound(); }catch(e){}
}
function setFocusVolume(v){
  S.focusVolume=+v; save();
  ['focusAudioLofi'].forEach(id=>{ const el=document.getElementById(id); if(el) el.volume=(+v)/100; });
}
function setFocusSound(mode,el){
  S.focusSound=mode; save();
  document.querySelectorAll('[data-focus-mode]').forEach(c=>c.classList.remove('on'));
  if(el) el.classList.add('on');
  const labels={lofi:'Lo-fi calmo'};
  const title={lofi:'Flow Lo-fi calmo'};
  const sub={lofi:'Ambiente suave incorporado no próprio app'};
  const chip=document.getElementById('focusSoundMode'); if(chip) chip.textContent=labels[mode]||'Lo-fi';
  const ttl=document.getElementById('focusSoundTitle'); if(ttl) ttl.textContent=title[mode]||'Flow Lo-fi interno';
  const subt=document.getElementById('focusSoundSub'); if(subt) subt.textContent=sub[mode]||'Som no próprio app';
  ensureFocusAudioLoaded(mode);
  if(focusPlaying) startFocusSound();
}


let foodSuggestIndex=-1;
