for(const food of EXTRA_FOODS){ if(!FOOD_DB.some(f=>normalizeFoodText?.(f.name||'')===normalizeFoodText?.(food.name||''))){ FOOD_DB.push(food); } }
FOOD_DB.sort((a,b)=>a.name.localeCompare(b.name,'pt-BR'));

function normalizeFoodText(v){ return (v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,''); }
function initFoodOptions(){ renderRecentFoods(); }
function getFoodMatches(query=''){
  const q=normalizeFoodText(query);
  if(!q) return FOOD_DB.slice(0,18);
  const starts=FOOD_DB.filter(f=>normalizeFoodText(f.name).startsWith(q));
  const includes=FOOD_DB.filter(f=>!normalizeFoodText(f.name).startsWith(q) && normalizeFoodText(f.name).includes(q));
  return [...starts,...includes].slice(0,18);
}
function getFoodItem(){
  const name=(document.getElementById('foodSearch')?.value||'').trim();
  if(!name) return null;
  return FOOD_DB.find(f=>normalizeFoodText(f.name)===normalizeFoodText(name)) || getFoodMatches(name)[0] || null;
}
function openFoodSuggests(matches){
  const list=document.getElementById('foodSuggestList'); if(!list) return;
  if(!matches || matches.length===0){ list.classList.remove('open'); list.innerHTML=''; foodSuggestIndex=-1; return; }
  list.innerHTML='';
  matches.forEach((item,idx)=>{
    const el=document.createElement('div');
    el.className='autocomplete-item'+(idx===foodSuggestIndex?' sel':'');
    el.innerHTML=`<strong>${item.name}</strong><span>${item.unit} · ${item.kcal} kcal · C ${item.carb}g · P ${item.prot}g · G ${item.fat}g</span>`;
    el.onmousedown=(e)=>{ e.preventDefault(); selectFoodItem(item.name); };
    list.appendChild(el);
  });
  list.classList.add('open');
}
function handleFoodSearchInput(){
  const input=document.getElementById('foodSearch'); if(!input) return;
  foodSuggestIndex=-1;
  openFoodSuggests(getFoodMatches(input.value));
  updateFoodPreview();
}
function selectFoodItem(name){
  const input=document.getElementById('foodSearch'); if(input) input.value=name;
  const list=document.getElementById('foodSuggestList'); if(list) list.classList.remove('open');
  foodSuggestIndex=-1;
  updateFoodPreview();
}
function calcFoodEntry(){
  const item=getFoodItem();
  const qty=Math.max(0.25, parseFloat(document.getElementById('mealQty')?.value||1) || 1);
  if(!item) return null;
  return { item, qty, kcal: Math.round(item.kcal*qty), carb:+(item.carb*qty).toFixed(1), prot:+(item.prot*qty).toFixed(1), fat:+(item.fat*qty).toFixed(1) };
}
function updateFoodPreview(){
  const box=document.getElementById('foodPreview'); if(!box) return;
  const entry=calcFoodEntry();
  if(!entry){ box.innerHTML='Digite para buscar e toque em um alimento da lista para o app estimar automaticamente calorias e macros.'; return; }
  box.innerHTML=`<strong>${entry.item.name}</strong> · ${entry.qty}× ${entry.item.unit}<br>${entry.kcal} kcal · C ${entry.carb}g · P ${entry.prot}g · G ${entry.fat}g`;
}
function clearFoodEntry(){
  const s=document.getElementById('foodSearch'); const q=document.getElementById('mealQty');
  if(s) s.value=''; if(q) q.value='1';
  const list=document.getElementById('foodSuggestList'); if(list) list.classList.remove('open');
  updateFoodPreview();
}
document.addEventListener('click',(e)=>{
  const list=document.getElementById('foodSuggestList'); const wrap=document.querySelector('.autocomplete-wrap');
  if(list && wrap && !wrap.contains(e.target)) list.classList.remove('open');
});
document.addEventListener('keydown',(e)=>{
  const list=document.getElementById('foodSuggestList'); const input=document.getElementById('foodSearch');
  if(!list || !input || !list.classList.contains('open')) return;
  const items=[...list.querySelectorAll('.autocomplete-item')];
  if(items.length===0) return;
  if(e.key==='ArrowDown'){ e.preventDefault(); foodSuggestIndex=(foodSuggestIndex+1)%items.length; openFoodSuggests(getFoodMatches(input.value)); }
  else if(e.key==='ArrowUp'){ e.preventDefault(); foodSuggestIndex=(foodSuggestIndex-1+items.length)%items.length; openFoodSuggests(getFoodMatches(input.value)); }
  else if(e.key==='Enter' && foodSuggestIndex>=0){ e.preventDefault(); const txt=items[foodSuggestIndex]?.querySelector('strong')?.textContent; if(txt) selectFoodItem(txt); }
  else if(e.key==='Escape'){ list.classList.remove('open'); }
});
function renderRecentFoods(){
  const wrap=document.getElementById('recentFoods'); if(!wrap) return;
  const rec=(S.recentFoods||[]).slice(0,8);
  if(rec.length===0){ wrap.innerHTML=''; return; }
  wrap.innerHTML='';
  rec.forEach(name=>{
    const b=document.createElement('button');
    b.className='chip';
    b.textContent=name;
    b.onclick=()=>{ selectFoodItem(name); updateFoodPreview(); };
    wrap.appendChild(b);
  });
}

