function renderFood(){
const total=S.meals.reduce((s,m)=>s+m.kcal,0);
const totalCarb=S.meals.reduce((s,m)=>s+(m.carb||0),0);
const totalProt=S.meals.reduce((s,m)=>s+(m.prot||0),0);
const totalFat=S.meals.reduce((s,m)=>s+(m.fat||0),0);
  const mealCount=S.meals.length;
  const fmc=document.getElementById('foodMealCount'); if(fmc) fmc.textContent=mealCount;
  const fpd=document.getElementById('foodProteinDay'); if(fpd) fpd.textContent=Math.round(totalProt)+'g';
  const fcd=document.getElementById('foodCarbDay'); if(fcd) fcd.textContent=Math.round(totalCarb)+'g';
  const ffd=document.getElementById('foodFatDay'); if(ffd) ffd.textContent=Math.round(totalFat)+'g';
const cd=document.getElementById('calTotalDisp'); if(cd) cd.textContent=total;
const cg=document.getElementById('calGoalDisp'); if(cg) cg.textContent=S.goals.calories;
const pct=Math.min(total/S.goals.calories*100,100);
const arc=document.getElementById('calArc');
if(arc) arc.style.strokeDashoffset=314-(314*pct/100);
const cv=document.getElementById('carbVal'); if(cv) cv.textContent=Math.round(totalCarb)+'g';
const pv=document.getElementById('protVal'); if(pv) pv.textContent=Math.round(totalProt)+'g';
const fv=document.getElementById('fatVal'); if(fv) fv.textContent=Math.round(totalFat)+'g';
const al=document.getElementById('calAlert'); if(al) al.style.display=total>S.goals.calories?'':'none';
renderMealBuilder();
const wrap=document.getElementById('mealList'); if(!wrap) return;
if(S.meals.length===0){wrap.innerHTML='<div class="empty">Nenhuma refeição registrada.</div>';}
else{
wrap.innerHTML='';
const cats=['☀️ Café da manhã','🥗 Almoço','🌙 Jantar','🍎 Lanche','💊 Suplemento'];
cats.forEach(cat=>{
const items=S.meals.filter(m=>m.cat===cat);
if(items.length===0) return;
const groups=[...new Set(items.map(m=>m.groupId||m.id))];
const h=document.createElement('div');
h.style.cssText='font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:1px;font-weight:700;margin:8px 0 6px';
h.textContent=cat;
wrap.appendChild(h);
groups.forEach(gid=>{
  const groupItems=items.filter(m=>(m.groupId||m.id)===gid);
  const sumK=groupItems.reduce((s,m)=>s+m.kcal,0);
  const sumC=groupItems.reduce((s,m)=>s+(m.carb||0),0);
  const sumP=groupItems.reduce((s,m)=>s+(m.prot||0),0);
  const sumF=groupItems.reduce((s,m)=>s+(m.fat||0),0);
  const card=document.createElement('div');
  card.style.cssText='background:var(--surface2);border:1px solid var(--border);border-radius:12px;padding:12px;margin-bottom:8px';
  card.innerHTML=`<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:8px"><div><div style="font-size:14px;font-weight:700">${cat}</div><div class="meal-cat">${groupItems[0].groupTime||'registrada'} · ${groupItems.length} item(ns)</div></div><div style="display:flex;align-items:center;gap:10px"><span class="meal-kcal">${Math.round(sumK)} kcal</span><button class="li-del" onclick="deleteMealGroup(${gid})">×</button></div></div><div style="font-size:12px;color:var(--text2);line-height:1.6">${groupItems.map(m=>`• ${m.food} (${m.qty}× ${m.unit})`).join('<br>')}</div><div class="meal-cat" style="margin-top:8px">C ${Math.round(sumC)}g · P ${Math.round(sumP)}g · G ${Math.round(sumF)}g</div>`;
  wrap.appendChild(card);
});
});
}
calcScore(); renderOverview();
}
function deleteMealGroup(groupId){
  S.meals=S.meals.filter(m=>(m.groupId||m.id)!==groupId); save(); renderFood();
}

