// HABITS
// ═══════════════════════════════════════════════════════════════════
function openAddHabit(){ document.getElementById('habitModal').classList.add('open'); }
function saveHabit(){
const name=document.getElementById('habitName').value.trim(); if(!name) return;
const cat=document.getElementById('habitCat').value;
const icon=document.getElementById('habitIcon').value||'⭐';
S.habits.push({id:Date.now(),name,cat,icon,streak:0});
['habitName','habitIcon'].forEach(id=>document.getElementById(id).value='');
save(); renderHabits(); closeModal('habitModal');
}
function toggleHabit(id){
const key=S.today+'*'+id;
if(S.habitLogs[key]) delete S.habitLogs[key];
else S.habitLogs[key]=1;
save(); renderHabits(); calcScore(); renderOverview();
}
function deleteHabit(id){
S.habits=S.habits.filter(h=>h.id!==id); save(); renderHabits();
}
function renderHabits(){
const wrap=document.getElementById('habitsList'); if(!wrap) return;
if(S.habits.length===0){wrap.innerHTML='<div class="empty">Nenhum hábito. Crie um acima!</div>'; renderHabitStats(); return;}
wrap.innerHTML='';
S.habits.forEach(h=>{
const done=!!S.habitLogs[S.today+'*'+h.id];
// calc streak
let streak=0;
const today=new Date();
for(let i=0;i<30;i++){
const d=new Date(today); d.setDate(d.getDate()-i);
const k=d.toDateString()+'*'+h.id;
if(S.habitLogs[k]) streak++;
else if(i>0) break;
}
const el=document.createElement('div');
el.className='habit-item';
el.innerHTML=`<div class="habit-check ${done?'done':''}" onclick="toggleHabit(${h.id})">${done?'✓':''}</div> <div class="habit-info"> <div class="habit-name">${h.icon} ${h.name}</div> <div class="habit-streak">${h.cat} · <span>${streak>0?'🔥 '+streak+' dias':'Ainda não feito'}</span></div> </div> <button class="li-del" onclick="deleteHabit(${h.id})">×</button>`;
wrap.appendChild(el);
});
renderHabitStats();
renderOverview();
}
function renderHabitStats(){
const wrap=document.getElementById('habitStats'); if(!wrap) return;
if(S.habits.length===0){wrap.innerHTML='<div class="empty">Sem dados.</div>';return;}
wrap.innerHTML='';
S.habits.forEach(h=>{
let total=0, done=0;
const today=new Date();
for(let i=0;i<7;i++){
const d=new Date(today); d.setDate(d.getDate()-i);
total++;
if(S.habitLogs[d.toDateString()+'*'+h.id]) done++;
}
const pct=Math.round(done/total*100);
const el=document.createElement('div');
el.style.cssText='margin-bottom:12px';
el.innerHTML=`<div style="display:flex;justify-content:space-between;margin-bottom:4px"> <span style="font-size:13px">${h.icon} ${h.name}</span> <span style="font-family:'DM Mono',monospace;font-size:11px;color:var(--habits)">${pct}% (7 dias)</span> </div> <div class="prog-wrap" style="--acc:var(--habits)"><div class="prog-bar" style="width:${pct}%;background:var(--habits)"></div></div>`;
wrap.appendChild(el);
});
}
function renderHeatmap(){
const wrap=document.getElementById('habitHeatmap'); if(!wrap) return;
wrap.innerHTML='';
const today=new Date();
for(let i=90;i>=0;i--){
const d=new Date(today); d.setDate(d.getDate()-i);
const doneCount=S.habits.filter(h=>S.habitLogs[d.toDateString()+'_'+h.id]).length;
const total=S.habits.length||1;
const pct=doneCount/total;
const cell=document.createElement('div');
cell.className='hm-cell'+(pct===0?'':pct<0.33?' l1':pct<0.66?' l2':pct<1?' l3':' l4');
cell.title=d.toLocaleDateString('pt-BR')+': '+doneCount+'/'+S.habits.length;
wrap.appendChild(cell);
}
}

