// Breathing 4-7-8
let breathRunning=false, breathPhase=0, breathSecs=0, breathCycles=0, breathInt=null;
const BREATH_PHASES=[{l:'Inspire',d:4,c:'inhale'},{l:'Segure',d:7,c:''},{l:'Expire',d:8,c:'exhale'}];
function toggleBreath(){
if(breathRunning){ stopBreath(); return; }
breathRunning=true; breathPhase=0; breathSecs=BREATH_PHASES[0].d;
document.getElementById('breathBtn').textContent='⏸ Pausar';
runBreath();
}
function runBreath(){
const phase=BREATH_PHASES[breathPhase];
const circle=document.getElementById('breathCircle');
const label=document.getElementById('breathLabel');
const count=document.getElementById('breathCount');
circle.className='breath-circle '+phase.c;
label.textContent=phase.l;
count.textContent=breathSecs;
breathInt=setInterval(()=>{
breathSecs--;
count.textContent=breathSecs;
if(breathSecs<=0){
clearInterval(breathInt);
breathPhase=(breathPhase+1)%3;
if(breathPhase===0) breathCycles++;
document.getElementById('breathCycles').textContent='Ciclos: '+breathCycles;
breathSecs=BREATH_PHASES[breathPhase].d;
if(breathRunning) runBreath();
}
},1000);
}
function stopBreath(){
clearInterval(breathInt); breathRunning=false;
document.getElementById('breathBtn').textContent='▶ Iniciar';
}
function resetBreath(){
stopBreath(); breathCycles=0; breathPhase=0; breathSecs=0;
document.getElementById('breathCircle').className='breath-circle';
document.getElementById('breathLabel').textContent='Toque para iniciar';
document.getElementById('breathCount').textContent='';
document.getElementById('breathCycles').textContent='Ciclos: 0';
}

// Meditation
let medRunning=false, medSecs=5*60, medInt=null;
function setMedTime(m,el){
medSecs=m*60; S.medMinutes=m;
document.querySelectorAll('#sec-mood .chip').forEach(c=>c.classList.remove('on'));
if(el) el.classList.add('on');
clearInterval(medInt); medRunning=false;
document.getElementById('medBtn').textContent='▶ Iniciar';
renderMedTimer();
}
function renderMedTimer(){
const m=Math.floor(medSecs/60),s=medSecs%60;
const el=document.getElementById('medTimer'); if(el) el.textContent=String(m).padStart(2,'0')+':'+String(s).padStart(2,'0');
}
function toggleMed(){
if(medRunning){ clearInterval(medInt); medRunning=false; document.getElementById('medBtn').textContent='▶ Continuar'; return; }
medRunning=true; document.getElementById('medBtn').textContent='⏸ Pausar';
medInt=setInterval(()=>{
medSecs--;
renderMedTimer();
if(medSecs<=0){
clearInterval(medInt); medRunning=false;
document.getElementById('medBtn').textContent='▶ Iniciar';
document.getElementById('medTimer').textContent='✅ Concluído!';
if(navigator.vibrate) navigator.vibrate([300,100,300]);
}
},1000);
}
function resetMed(){
clearInterval(medInt); medRunning=false;
medSecs=(S.medMinutes||5)*60;
document.getElementById('medBtn').textContent='▶ Iniciar';
renderMedTimer();
}

// ═══════════════════════════════════════════════════════════════════
// OVERVIEW
// ═══════════════════════════════════════════════════════════════════
function renderOverview(){
const waterGoalCups=getWaterGoalCups();
const waterCurrentMl=S.water*Math.max(50,S.cupSize||250);
const waterGoalMl=calcWaterGoalMl();
const ow=document.getElementById('ov-water'); if(ow) ow.textContent=S.water+'/'+waterGoalCups;
const owb=document.getElementById('ovb-water'); if(owb) owb.style.width=Math.min(waterCurrentMl/waterGoalMl*100,100)+'%';
const os=document.getElementById('ov-study'); if(os) os.textContent=S.pomsDone+' pomos';
const osb=document.getElementById('ovb-study'); if(osb) osb.style.width=Math.min(S.pomsDone/(S.goals.pomodoros||4)*100,100)+'%';
const td=S.tasks.filter(t=>t.done).length, tt=S.tasks.length;
const ot=document.getElementById('ov-work'); if(ot) ot.textContent=td+'/'+tt;
const otb=document.getElementById('ovb-work'); if(otb) otb.style.width=(tt?td/tt*100:0)+'%';
const oh=document.getElementById('ov-health'); if(oh) oh.textContent=S.steps.toLocaleString('pt-BR')+' passos';
const ohb=document.getElementById('ovb-health'); if(ohb) ohb.style.width=Math.min(S.steps/S.goals.steps*100,100)+'%';
const hrs=getSleepHours();
const osl=document.getElementById('ov-sleep'); if(osl) osl.textContent=hrs?hrs+'h':'—h';
const oslb=document.getElementById('ovb-sleep'); if(oslb) oslb.style.width=hrs?Math.min(hrs/S.goals.sleep*100,100)+'%':'0%';
const cal=S.meals.reduce((s,m)=>s+m.kcal,0);
const of=document.getElementById('ov-food'); if(of) of.textContent=cal+' kcal';
const ofb=document.getElementById('ovb-food'); if(ofb) ofb.style.width=Math.min(cal/S.goals.calories*100,100)+'%';
const hd=S.habits.filter(h=>S.habitLogs[S.today+'_'+h.id]).length;
const oha=document.getElementById('ov-habits'); if(oha) oha.textContent=hd+'/'+S.habits.length;
const ohab=document.getElementById('ovb-habits'); if(ohab) ohab.style.width=(S.habits.length?hd/S.habits.length*100:0)+'%';
const moodLabels=['','😞','😕','😐','🙂','😄'];
const om=document.getElementById('ov-mood'); if(om) om.textContent=S.mood?moodLabels[S.mood]:'—';
const omb=document.getElementById('ovb-mood'); if(omb) omb.style.width=S.mood?S.mood/5*100+'%':'0%';
calcScore();
}

// ═══════════════════════════════════════════════════════════════════
// CHARTS
// ═══════════════════════════════════════════════════════════════════
function getWeekDays(){
const days=['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
const res=[];
for(let i=6;i>=0;i--){
const d=new Date(); d.setDate(d.getDate()-i);
res.push({label:days[d.getDay()],date:d.toDateString()});
}
return res;
}
function renderBarChart(wrap,vals,labels){
if(!wrap) return;
wrap.innerHTML='';
const max=Math.max(...vals,1);
vals.forEach((v,i)=>{
const col=document.createElement('div');
col.className='bar-col';
const h=Math.round(v/max*100)+'%';
col.innerHTML=`<div class="bar" style="height:${h};min-height:${v>0?'3px':'0'}"></div><div class="bar-lbl">${labels?labels[i]:''}</div>`;
wrap.appendChild(col);
});
}
function renderCharts(){
const week=getWeekDays();
// Water chart
const wc=document.getElementById('waterChart');
if(wc) renderBarChart(wc,week.map(d=>S.history[d.date]?.water||0),week.map(d=>d.label));
// Study chart
const sc=document.getElementById('studyChart');
if(sc) renderBarChart(sc,week.map(d=>S.history[d.date]?.pomos||0),week.map(d=>d.label));
// Steps chart
const stc=document.getElementById('stepsChart');
if(stc) renderBarChart(stc,week.map(d=>S.history[d.date]?.steps||0),week.map(d=>d.label));
// Sleep chart
const slc=document.getElementById('sleepChart');
if(slc) renderBarChart(slc,week.map(d=>S.history[d.date]?.sleep||0),week.map(d=>d.label));
const sa=document.getElementById('sleepAvg');
const sleepVals=week.map(d=>S.history[d.date]?.sleep||0).filter(v=>v>0);
if(sa&&sleepVals.length) sa.textContent='média '+(sleepVals.reduce((a,b)=>a+b,0)/sleepVals.length).toFixed(1)+'h';
// Food chart
const fc=document.getElementById('foodChart');
if(fc) renderBarChart(fc,week.map(d=>S.history[d.date]?.calories||0),week.map(d=>d.label));
// Mood chart
const mc=document.getElementById('moodChart');
if(mc) renderBarChart(mc,week.map(d=>S.history[d.date]?.mood||0),week.map(d=>d.label));
// Overview / weekly score
const wk=document.getElementById('weekChart');
if(wk) renderBarChart(wk,week.map(d=>S.history[d.date]?.score||0),week.map(d=>d.label));
// compare
const wc2=document.getElementById('weekCompare');
if(wc2){
const yesterday=new Date(); yesterday.setDate(yesterday.getDate()-1);
const yd=S.history[yesterday.toDateString()];
if(yd) wc2.textContent='Ontem: '+yd.score+'% · Esta semana';
}
}

