// ═══════════════════════════════════════════════════════════════════
function confetti(){
const colors=['#c084fc','#22d3ee','#34d399','#fb923c','#f472b6','#fbbf24'];
for(let i=0;i<30;i++){
const p=document.createElement('div');
p.className='confetti-piece';
p.style.cssText=`left:${Math.random()*100}vw;top:-10px;background:${colors[Math.floor(Math.random()*colors.length)]};animation-delay:${Math.random()*0.5}s;animation-duration:${1+Math.random()}s`;
document.body.appendChild(p);
setTimeout(()=>p.remove(),2000);
}
}

