function closeModal(id){
document.getElementById(id).classList.remove('open');
}
document.querySelectorAll('.modal-bg').forEach(m=>{
m.addEventListener('click',e=>{ if(e.target===m) m.classList.remove('open'); });
});

document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') toggleSideMenu(false);
});
let sideStartY = null;
document.addEventListener('touchstart', (e) => {
  const menu = document.getElementById('sideMenu');
  if (!menu || !menu.classList.contains('open')) return;
  if (menu.contains(e.target)) sideStartY = e.touches[0].clientY;
}, {passive:true});
document.addEventListener('touchmove', (e) => {
  const body = document.getElementById('sideMenuBody');
  const menu = document.getElementById('sideMenu');
  if (!body || !menu || !menu.classList.contains('open')) return;
  if (!menu.contains(e.target)) return;
  // Keep drawer scrollable inside PWA/iOS
  const atTop = body.scrollTop <= 0;
  const atBottom = Math.ceil(body.scrollTop + body.clientHeight) >= body.scrollHeight;
  const currentY = e.touches[0].clientY;
  const movingDown = sideStartY !== null && currentY > sideStartY;
  const movingUp = sideStartY !== null && currentY < sideStartY;
  if ((atTop && movingDown) || (atBottom && movingUp)) {
    e.preventDefault();
  }
}, {passive:false});
document.addEventListener('dblclick', function(e){ e.preventDefault(); }, {passive:false});

