    return `${String(start.getDate()).padStart(2,'0')} ${monthNames[start.getMonth()]} ${start.getFullYear()} – ${String(end.getDate()).padStart(2,'0')} ${monthNames[end.getMonth()]} ${end.getFullYear()}`;
